/// Executor for UserAnonymizationRequest flow
pub struct UserAnonymizationRequestFlowExecutor<H: UserAnonymizationRequestStepHandler> {
    handler: Arc<H>,
}

impl<H: UserAnonymizationRequestStepHandler> UserAnonymizationRequestFlowExecutor<H> {
    /// Create a new flow executor
    pub fn new(handler: Arc<H>) -> Self {
        Self { handler }
    }

    /// Start a new flow instance
    pub async fn start(&self, instance_id: impl Into<String>) -> Result<UserAnonymizationRequestFlowInstance, FlowError> {
        let mut instance = UserAnonymizationRequestFlowInstance::new(instance_id);
        instance.status = UserAnonymizationRequestFlowStatus::Running;
        instance.current_step = Some(UserAnonymizationRequestFlowStep::FetchUserDetails);
        Ok(instance)
    }

    /// Execute the current step
    pub async fn execute_step(&self, instance: &mut UserAnonymizationRequestFlowInstance) -> Result<(), FlowError> {
        let current_step = match instance.current_step {
            Some(step) => step,
            None => return Err(FlowError::NoCurrentStep),
        };

        let next_step = match current_step {
            UserAnonymizationRequestFlowStep::FetchUserDetails => {
                self.handler.handle_fetch_user_details(instance).await?
            }
            UserAnonymizationRequestFlowStep::LogUserNotFound => {
                self.handler.handle_log_user_not_found(instance).await?
            }
            UserAnonymizationRequestFlowStep::ValidateRequest => {
                self.handler.handle_validate_request(instance).await?
            }
            UserAnonymizationRequestFlowStep::CheckValidation => {
                let next = self.handler.evaluate_check_validation(instance).await?;
                Some(next)
            }
            UserAnonymizationRequestFlowStep::LogValidationError => {
                self.handler.handle_log_validation_error(instance).await?
            }
            UserAnonymizationRequestFlowStep::CreateRecord => {
                self.handler.handle_create_record(instance).await?
            }
            UserAnonymizationRequestFlowStep::LogRecordError => {
                self.handler.handle_log_record_error(instance).await?
            }
            UserAnonymizationRequestFlowStep::UpdateStatusProcessing => {
                self.handler.handle_update_status_processing(instance).await?
            }
            UserAnonymizationRequestFlowStep::AnonymizeUserData => {
                self.handler.handle_anonymize_user_data(instance).await?
            }
            UserAnonymizationRequestFlowStep::LogAnonymizationError => {
                self.handler.handle_log_anonymization_error(instance).await?
            }
            UserAnonymizationRequestFlowStep::UpdateStatusCompleted => {
                self.handler.handle_update_status_completed(instance).await?
            }
            UserAnonymizationRequestFlowStep::InvalidateSessions => {
                self.handler.handle_invalidate_sessions(instance).await?
            }
            UserAnonymizationRequestFlowStep::LogCompletion => {
                self.handler.handle_log_completion(instance).await?
            }
            UserAnonymizationRequestFlowStep::MarkFailed => {
                self.handler.handle_mark_failed(instance).await?
            }
            UserAnonymizationRequestFlowStep::NotifyComplete => {
                self.handler.handle_notify_complete(instance).await?
            }
            UserAnonymizationRequestFlowStep::Complete => {
                self.handler.handle_complete(instance).await?;
                None // Terminal step
            }
            UserAnonymizationRequestFlowStep::WorkflowFailed => {
                self.handler.handle_workflow_failed(instance).await?;
                None // Terminal step
            }
        };

        // Mark current step as completed
        instance.completed_steps.push(current_step);

        // Move to next step
        match next_step {
            Some(next) => {
                instance.current_step = Some(next);
            }
            None => {
                instance.current_step = None;
                instance.status = UserAnonymizationRequestFlowStatus::Completed;
            }
        }

        instance.updated_at = chrono::Utc::now();
        Ok(())
    }

    /// Run the flow to completion
    pub async fn run(&self, instance: &mut UserAnonymizationRequestFlowInstance) -> Result<(), FlowError> {
        while !instance.is_complete() && instance.status != UserAnonymizationRequestFlowStatus::Waiting {
            self.execute_step(instance).await?;
        }
        Ok(())
    }

    /// Cancel the flow
    pub fn cancel(&self, instance: &mut UserAnonymizationRequestFlowInstance) {
        instance.status = UserAnonymizationRequestFlowStatus::Cancelled;
        instance.updated_at = chrono::Utc::now();
    }

    /// Mark flow as failed
    pub fn fail(&self, instance: &mut UserAnonymizationRequestFlowInstance, error: impl Into<String>) {
        instance.status = UserAnonymizationRequestFlowStatus::Failed;
        instance.error = Some(error.into());
        instance.updated_at = chrono::Utc::now();
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_flow_instance_creation() {
        let instance = UserAnonymizationRequestFlowInstance::new("test-1");
        assert_eq!(instance.id, "test-1");
        assert_eq!(instance.status, UserAnonymizationRequestFlowStatus::Pending);
        assert!(!instance.is_complete());
    }

    #[test]
    fn test_flow_context() {
        let mut instance = UserAnonymizationRequestFlowInstance::new("test-2");
        instance.set_context("key", serde_json::json!("value"));
        let value = instance.get_context("key");
        assert_eq!(value, Some(&serde_json::json!("value")));
    }

    #[test]
    fn test_flow_status_transitions() {
        let mut instance = UserAnonymizationRequestFlowInstance::new("test-3");
        assert!(!instance.is_running());

        instance.status = UserAnonymizationRequestFlowStatus::Running;
        assert!(instance.is_running());
        assert!(!instance.is_complete());

        instance.status = UserAnonymizationRequestFlowStatus::Completed;
        assert!(instance.is_complete());
        assert!(!instance.is_running());
    }
}
